SELECT /*+ INDEX_DESC(A PPS_RCG_IDX1) */ SEQ, B.SUBSCRIBER_NO, NVL(A.CONTRACT_NUM,'') CONTRACT_NUM, NVL(REQ_SRC,'-') REQ_SRC, NVL(REQ_TYPE,'-') REQ_TYPE, NVL(RECHARGE_INFO,'-') RECHARGE_INFO, NVL(RECHARGE_METHOD,'-') RECHARGE_METHOD, NVL(AMOUNT,0) AMOUNT, NVL(IN_AMOUNT,0) IN_AMOUNT, NVL(KT_RES_CODE,'-') KT_RES_CODE, DECODE(KT_RES_CODE,'0000', '성공', '', '', '실패') KT_RES_CODE_NM, NVL(TO_CHAR(KT_RES_DT, 'YYYY-MM-DD HH24:MI:SS'),'-') KT_RES_DT, NVL(ADMIN_ID,'-') ADMIN_ID, NVL(RECHARGE_AGENT,'-') RECHARGE_AGENT, NVL(FN_GET_ORGNM(RECHARGE_AGENT),'-') RECHARGE_AGENT_NAME, NVL(CHG_TYPE,'-') CHG_TYPE, NVL(F_GET_KT_CODE_NM('PPS_RCG','CHG_TYPE',CHG_TYPE),'-') CHG_TYPE_NAME, NVL(CANCEL_FLAG,'-') CANCEL_FLAG, NVL(TO_CHAR(CANCEL_DT,'YYYY-MM-DD'),'-') CANCEL_DT, NVL(BASIC_REMAINS,0) BASIC_REMAINS, NVL(TO_CHAR(RECHARGE_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') RECHARGE_DATE, DECODE(KT_RES_CODE, '0000', '취소', '') cancelBtn, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'-') BASIC_EXPIRE, REMARK FROM PPS_RCG A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND RECHARGE_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND AMOUNT > 0 AND RECHARGE_DATE < SYSDATE AND AGENT_ID = #{agentId}
AND A.CONTRACT_NUM = #{searchNm}
AND A.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND RECHARGE_INFO = #{searchNm}
AND RECHARGE_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND RECHARGE_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND REQ_SRC = #{searchReqSrc}
AND CHG_TYPE = #{searchChgType}
AND (REQ_TYPE = 'CMS_RCG_VOICE' OR REQ_TYPE = 'CMS_RCG_DATA')
AND (REQ_TYPE = 'POS_RCG_VOICE' OR REQ_TYPE = 'POS_RCG_DATA')
AND RECHARGE_METHOD = #{searchRechargeMethod}
AND KT_RES_CODE = '0000'
AND (KT_RES_CODE <> '0000' OR KT_RES_CODE IS NULL)
AND CANCEL_FLAG = #{searchCancelFlag}

SELECT /*+ INDEX_DESC(A PPS_RCG_IDX1) */ SEQ, NVL(B.SUBSCRIBER_NO, '-')SUBSCRIBER_NO, NVL(A.CONTRACT_NUM,'') CONTRACT_NUM, NVL(REQ_SRC,'-') REQ_SRC, NVL(REQ_TYPE,'-') REQ_TYPE, NVL(RECHARGE_INFO,'-') RECHARGE_INFO, NVL(RECHARGE_METHOD,'-') RECHARGE_METHOD, NVL(AMOUNT,0) AMOUNT, NVL(IN_AMOUNT,0) IN_AMOUNT, NVL(KT_RES_CODE,'-') KT_RES_CODE, DECODE(KT_RES_CODE,'0000', '성공', '', '-', '실패') KT_RES_CODE_NM, NVL(TO_CHAR(KT_RES_DT, 'YYYY-MM-DD HH24:MI:SS'),'-') KT_RES_DT, NVL(ADMIN_ID,'-') ADMIN_ID, NVL(RECHARGE_AGENT,'-') RECHARGE_AGENT, NVL(FN_GET_ORGNM(RECHARGE_AGENT),'-') RECHARGE_AGENT_NAME, NVL(CHG_TYPE,'-') CHG_TYPE, NVL(F_GET_KT_CODE_NM('PPS_RCG','CHG_TYPE',CHG_TYPE),'-') CHG_TYPE_NAME, NVL(CANCEL_FLAG,'-') CANCEL_FLAG, NVL(TO_CHAR(CANCEL_DT,'YYYY-MM-DD'),'-') CANCEL_DT, NVL(BASIC_REMAINS,0) BASIC_REMAINS, NVL(TO_CHAR(RECHARGE_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') RECHARGE_DATE, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'-') BASIC_EXPIRE, NVL(DECODE(KT_RES_CODE, '4002', '미가입고객', REMARK), '-') REMARK FROM PPS_RCG A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND RECHARGE_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND AMOUNT > 0 AND RECHARGE_DATE < SYSDATE AND AGENT_ID = #{agentId}
AND A.CONTRACT_NUM = #{searchNm}
AND A.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND RECHARGE_INFO = #{searchNm}
AND RECHARGE_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND RECHARGE_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND REQ_SRC = #{searchReqSrc}
AND CHG_TYPE = #{searchChgType}
AND (REQ_TYPE = 'CMS_RCG_VOICE' OR REQ_TYPE = 'CMS_RCG_DATA')
AND (REQ_TYPE = 'POS_RCG_VOICE' OR REQ_TYPE = 'POS_RCG_DATA')
AND RECHARGE_METHOD = #{searchRechargeMethod}
AND KT_RES_CODE = '0000'
AND (KT_RES_CODE <> '0000' OR KT_RES_CODE IS NULL)
AND CANCEL_FLAG = #{searchCancelFlag}

	{CALL P_KT_IN_REQ(
			    #{seq, jdbcType=VARCHAR}, #{reqType, jdbcType=VARCHAR}, #{ip, jdbcType=VARCHAR}, #{contractNum, jdbcType=VARCHAR}, #{subscriberNo, jdbcType=VARCHAR}, #{amount, jdbcType=VARCHAR}, #{dataVaId, jdbcType=VARCHAR}, #{dataVaRemains, jdbcType=VARCHAR}, #{dataQuota, jdbcType=VARCHAR}, #{dataMode, jdbcType=VARCHAR}, #{nasIp, jdbcType=VARCHAR}, #{topupGubun, jdbcType=VARCHAR}, #{rechargeInfo, jdbcType=VARCHAR}, #{rechargeAgent, jdbcType=VARCHAR}, #{adminId, jdbcType=VARCHAR}, #{accessId, jdbcType=VARCHAR}, #{remark, jdbcType=VARCHAR}
			   ,#{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }

	{call p_rcg_bill(
			    #{opCode, jdbcType=VARCHAR}
			    , #{seq, jdbcType=VARCHAR}
			    , #{reqType, jdbcType=VARCHAR}
			    , #{subscriberNo, jdbcType=VARCHAR}
			    , #{recharge, jdbcType=VARCHAR}
			    , #{rechargeInfo, jdbcType=VARCHAR}
			    , #{agentId, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR}
			    , #{ip, jdbcType=VARCHAR}
			    , #{dataVaId, jdbcType=VARCHAR}
			    , #{topupGubun, jdbcType=VARCHAR}
			   ,#{seq, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }
